import glob

# Fix all LRO files that have .ToObjectFromJson<Dictionary<string, string>>()
files = [
    'Resources/Generated/LongRunningOperation/ResourcesArmOperation.cs',
    'Resources/Generated/LongRunningOperation/ResourcesArmOperationOfT.cs',
    'ManagementGroup/Generated/LongRunningOperation/ManagementGroupsArmOperation.cs',
    'ManagementGroup/Generated/LongRunningOperation/ManagementGroupsArmOperationOfT.cs',
]
for f in files:
    with open(f, 'r') as fh:
        content = fh.read()
    # Replace the GetOperationId method body
    old = '''var lroDetails = ModelReaderWriter.Write(rehydrationToken, ModelReaderWriterOptions.Json, AzureResourceManagerContext.Default).ToObjectFromJson<Dictionary<string, string>>();
            return lroDetails[\"id\"];'''
    new = '''var data = ModelReaderWriter.Write(rehydrationToken, ModelReaderWriterOptions.Json, AzureResourceManagerContext.Default);
            using var doc = JsonDocument.Parse(data);
            return doc.RootElement.GetProperty(\"id\").GetString();'''
    if old in content:
        content = content.replace(old, new)
        # Add using System.Text.Json if not present
        if 'using System.Text.Json;' not in content:
            content = content.replace('using System.ClientModel.Primitives;', 'using System.ClientModel.Primitives;\nusing System.Text.Json;')
        # Remove Dictionary using if no longer needed
        if 'Dictionary<' not in content.replace(old, ''):
            pass  # keep it, it may be used elsewhere
        with open(f, 'w') as fh:
            fh.write(content)
        print(f'Fixed: {f}')
    else:
        print(f'Pattern not found in: {f}')
"
